const data = $input.item.json.body || $input.item.json;
const itemName   = data.itemName   || 'Unknown Item';
const oldPrice   = parseFloat(data.oldPrice   || 0);
const newPrice   = parseFloat(data.newPrice   || 0);
const changedBy  = data.changedBy  || 'System';

if(newPrice <= oldPrice) return [];  // Only alert when price increases

const diff    = newPrice - oldPrice;
const pct     = oldPrice > 0 ? ((diff/oldPrice)*100).toFixed(1) : 'N/A';
const now     = new Date().toLocaleString('ur-PK',{timeZone:'Asia/Karachi'});

const msg = `💹 <b>CHAYE CAFE — Price Change Alert!</b>

🕐 Time: ${now}
📦 Item: <b>${itemName}</b>
📉 Old Price: Rs. ${oldPrice.toFixed(0)}
📈 New Price: <b>Rs. ${newPrice.toFixed(0)}</b>
⬆️ Increase: Rs. ${diff.toFixed(0)} (+${pct}%)
👤 Changed By: ${changedBy}

✅ Price update ho gaya hai!`;

return [{json:{message:msg}}];
